// === VALIDATION & ERROR HANDLING ===
const message = $input.first().json.message;
const chat = $input.first().json.chat;

// Валидация входных данных
if (!message || !message.text) {
  throw new Error('Invalid message format: missing text');
}

if (!chat || !chat.id) {
  throw new Error('Invalid chat format: missing chat.id');
}

const chatId = String(chat.id);
const text = String(message.text).trim();

// Проверка на пустое сообщение
if (text.length === 0) {
  return [{
    json: {
      chatId: chatId,
      message: '',
      isEmpty: true,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    chatId: chatId,
    message: text,
    isEmpty: false,
    timestamp: new Date().toISOString(),
    userName: chat.username || chat.first_name || 'Unknown',
    chatType: chat.type
  }
}];

// === MEMORY HUB (SHARED) ===
// Централизованное управление памятью сессий
// В production заменить на вызов Redis/PostgreSQL через HTTP Request

const chatId = $input.first().json.chatId;
const userMessage = $input.first().json.message;
const timestamp = new Date().toISOString();

// Ключ сессии
const sessionKey = `session:${chatId}`;

// Имитация хранилища сессий (в production использовать $getWorkflowStaticData или внешнюю БД)
let session = {};

// Попытка получить существующую сессию из статических данных workflow
try {
  const staticData = $getWorkflowStaticData();
  if (staticData.sessions && staticData.sessions[sessionKey]) {
    session = staticData.sessions[sessionKey];
  } else {
    // Инициализация новой сессии
    session = {
      chatId: chatId,
      createdAt: timestamp,
      updatedAt: timestamp,
      messageCount: 0,
      history: [],
      context: {
        currentAgent: 'orchestrator',
        lastIntent: null,
        skills: ['calendar', 'default']
      },
      metadata: {
        language: 'ru',
        timezone: 'Asia/Yekaterinburg'
      }
    };
  }
} catch (error) {
  // При ошибке создаём новую сессию
  session = {
    chatId: chatId,
    createdAt: timestamp,
    updatedAt: timestamp,
    messageCount: 0,
    history: [],
    context: {
      currentAgent: 'orchestrator',
      lastIntent: null,
      skills: ['calendar', 'default']
    },
    metadata: {
      language: 'ru',
      timezone: 'Asia/Yekaterinburg'
    }
  };
}

// Добавляем сообщение пользователя в историю
session.history.push({
  role: 'user',
  content: userMessage,
  timestamp: timestamp
});

// Ограничиваем историю последними 10 сообщениями
if (session.history.length > 10) {
  session.history = session.history.slice(-10);
}

session.messageCount += 1;
session.updatedAt = timestamp;

// Сохраняем сессию в статические данные workflow
try {
  const staticData = $getWorkflowStaticData();
  if (!staticData.sessions) {
    staticData.sessions = {};
  }
  staticData.sessions[sessionKey] = session;
} catch (error) {
  console.error('Failed to save session to static data:', error.message);
}

return [{
  json: {
    ...$input.first().json,
    sessionId: sessionKey,
    session: session,
    messageHistory: session.history,
    sessionContext: session.context,
    metadata: session.metadata,
    isNewSession: session.messageCount === 1
  }
}];

// === ORCHESTRATOR RESPONSE VALIDATION ===

const orchestratorOutput = $input.first().json;

try {
  // Парсим ответ от LLM (может быть строкой или объектом)
  let parsed;
  if (typeof orchestratorOutput.choices !== 'undefined') {
    // Формат OpenAI API
    const content = orchestratorOutput.choices[0]?.message?.content;
    parsed = typeof content === 'string' ? JSON.parse(content) : content;
  } else if (typeof orchestratorOutput.selectedSkill !== 'undefined') {
    // Уже распаршено
    parsed = orchestratorOutput;
  } else {
    throw new Error('Unknown response format');
  }

  // Валидация обязательных полей
  if (!parsed.selectedSkill || !parsed.task) {
    throw new Error('Missing required fields: selectedSkill or task');
  }

  // Нормализация confidence
  parsed.confidence = parseFloat(parsed.confidence) || 0.5;

  // Если низкая уверенность → переключаем на default
  if (parsed.confidence < 0.6) {
    parsed.selectedSkill = 'default';
    parsed.task = 'clarify';
    parsed.reasoning = 'Low confidence, routing to clarification';
  }

  return [{
    json: {
      ...orchestratorOutput,
      routedTo: parsed.selectedSkill,
      task: parsed.task,
      params: parsed.params || {},
      confidence: parsed.confidence,
      reasoning: parsed.reasoning
    }
  }];

} catch (error) {
  // При ошибке парсинга → default агент
  console.error('Orchestrator parsing error:', error.message);

  return [{
    json: {
      ...orchestratorOutput,
      routedTo: 'default',
      task: 'clarify',
      params: {},
      confidence: 0.0,
      reasoning: 'Parse error, fallback to default',
      error: error.message
    }
  }];
}

// === CALENDAR TOOLS EXECUTOR ===
// Полная реализация инструментов календаря с валидацией и обработкой ошибок

const task = $input.first().json.task;
const params = $input.first().json.params || {};
const timezone = $input.first().json.metadata?.timezone || 'Asia/Yekaterinburg';
const chatId = $input.first().json.chatId;
const messageHistory = $input.first().json.messageHistory || [];

// Вспомогательная функция для парсинга дат из естественного языка
function parseDateFromText(text) {
  // Упрощённая реализация - в production использовать NLP библиотеку
  const now = new Date();

  if (text.includes('завтра')) {
    return new Date(now.setDate(now.getDate() + 1)).toISOString();
  }
  if (text.includes('сегодня')) {
    return now.toISOString();
  }

  // Попытка найти дату в формате YYYY-MM-DD или DD.MM.YYYY
  const dateRegex = /(\d{4}-\d{2}-\d{2}|\d{2}\.\d{2}\.\d{4})/;
  const match = text.match(dateRegex);
  if (match) {
    return new Date(match[0]).toISOString();
  }

  return null;
}

// Извлечение параметров из истории сообщений
function extractMissingParamsFromHistory(missingField, history) {
  const lastMessages = history.slice(-3).map(m => m.content).join(' ');

  if (missingField === 'title') {
    // Пытаемся извлечь название из сообщения
    const titleMatch = lastMessages.match(/(?:встреч[ау]|событи[ея]|звонок|обед)[\s]+(?:с\s+)?([^
,.!?]+)/i);
    if (titleMatch) return titleMatch[1].trim();
  }

  if (missingField === 'datetime') {
    return parseDateFromText(lastMessages);
  }

  return null;
}

// Реализация инструментов календаря
const calendarTools = {

  create_event: async (params) => {
    // Проверка на наличие необходимых параметров
    if (!params.title) {
      // Пытаемся извлечь из истории
      const extractedTitle = extractMissingParamsFromHistory('title', messageHistory);
      if (extractedTitle) {
        params.title = extractedTitle;
      } else {
        return {
          success: false,
          requiresFollowup: true,
          message: 'Как называется событие?',
          missingField: 'title',
          action: 'create_event'
        };
      }
    }

    if (!params.date && !params.datetime) {
      const extractedDate = extractMissingParamsFromHistory('datetime', messageHistory);
      if (extractedDate) {
        params.datetime = extractedDate;
      } else {
        return {
          success: false,
          requiresFollowup: true,
          message: 'На какую дату и время запланировать событие?',
          missingField: 'datetime',
          action: 'create_event'
        };
      }
    }

    // Установка значения по умолчанию для длительности
    if (!params.duration) {
      params.duration = 60; // минут
    }

    // Генерация уникального ID события
    const eventId = `evt_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const eventDatetime = params.date || params.datetime;

    // Форматирование даты для вывода
    let formattedDate;
    try {
      const dateObj = new Date(eventDatetime);
      formattedDate = dateObj.toLocaleString('ru-RU', {
        timeZone: timezone,
        day: 'numeric',
        month: 'long',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (e) {
      formattedDate = eventDatetime;
    }

    return {
      success: true,
      action: 'create_event',
      data: {
        eventId: eventId,
        title: params.title,
        datetime: eventDatetime,
        duration: params.duration,
        description: params.description || '',
        timezone: timezone,
        createdAt: new Date().toISOString()
      },
      message: `✅ Событие "${params.title}" создано\n📅 ${formattedDate}\n⏱️ Длительность: ${params.duration} мин.`,
      requiresFollowup: false
    };
  },

  read_events: async (params) => {
    const fromDate = params.fromDate ? new Date(params.fromDate) : new Date();
    const toDate = params.toDate 
      ? new Date(params.toDate) 
      : new Date(Date.now() + 7 * 24 * 60 * 60 * 1000); // +7 дней

    // Mock-данные событий (в production заменить на API вызов)
    const mockEvents = [
      {
        eventId: 'evt_001',
        title: 'Встреча с командой',
        datetime: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000).toISOString(),
        duration: 60,
        description: 'Еженедельный синк'
      },
      {
        eventId: 'evt_002',
        title: 'Обед с клиентом',
        datetime: new Date(Date.now() + 3 * 24 * 60 * 60 * 1000 + 5 * 60 * 60 * 1000).toISOString(),
        duration: 90,
        description: 'Обсуждение контракта'
      },
      {
        eventId: 'evt_003',
        title: 'Презентация проекта',
        datetime: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000).toISOString(),
        duration: 120,
        description: 'Финальная презентация'
      }
    ];

    // Фильтрация событий по диапазону дат
    const filteredEvents = mockEvents.filter(e => {
      const eventDate = new Date(e.datetime);
      return eventDate >= fromDate && eventDate <= toDate;
    });

    // Форматирование списка событий
    let eventsList = '';
    filteredEvents.forEach((event, index) => {
      const dateStr = new Date(event.datetime).toLocaleString('ru-RU', {
        timeZone: timezone,
        weekday: 'short',
        day: 'numeric',
        month: 'short',
        hour: '2-digit',
        minute: '2-digit'
      });
      eventsList += `${index + 1}. ${event.title}\n   📅 ${dateStr} (${event.duration} мин.)\n`;
    });

    if (filteredEvents.length === 0) {
      return {
        success: true,
        action: 'read_events',
        data: { events: [], count: 0 },
        message: '📅 На ближайшую неделю событий не запланировано.',
        requiresFollowup: false
      };
    }

    return {
      success: true,
      action: 'read_events',
      data: {
        events: filteredEvents,
        count: filteredEvents.length,
        dateRange: { from: fromDate.toISOString(), to: toDate.toISOString() }
      },
      message: `📅 События на период:\n\n${eventsList}`,
      requiresFollowup: false
    };
  },

  update_event: async (params) => {
    if (!params.eventId && !params.title) {
      const extractedTitle = extractMissingParamsFromHistory('title', messageHistory);
      if (extractedTitle) {
        params.title = extractedTitle;
      } else {
        return {
          success: false,
          requiresFollowup: true,
          message: 'Какое событие нужно обновить? Укажите название или дату.',
          missingField: 'eventId',
          action: 'update_event'
        };
      }
    }

    // Проверка что именно обновляем
    const hasUpdates = params.newTitle || params.newDatetime || params.newDuration || params.newDescription;
    if (!hasUpdates) {
      return {
        success: false,
        requiresFollowup: true,
        message: 'Что нужно изменить в событии? (время, название, длительность)',
        missingField: 'updateData',
        action: 'update_event'
      };
    }

    // Mock обновление
    const eventId = params.eventId || `evt_by_title_${params.title}`;
    const updates = [];
    if (params.newTitle) updates.push(`название → "${params.newTitle}"`);
    if (params.newDatetime) updates.push(`время → ${params.newDatetime}`);
    if (params.newDuration) updates.push(`длительность → ${params.newDuration} мин.`);

    return {
      success: true,
      action: 'update_event',
      data: {
        eventId: eventId,
        updated: true,
        changes: updates
      },
      message: `✅ Событие обновлено:\n${updates.map(u => '  • ' + u).join('\n')}`,
      requiresFollowup: false
    };
  },

  delete_event: async (params) => {
    if (!params.eventId && !params.title) {
      const extractedTitle = extractMissingParamsFromHistory('title', messageHistory);
      if (extractedTitle) {
        params.title = extractedTitle;
      } else {
        return {
          success: false,
          requiresFollowup: true,
          message: 'Какое событие нужно удалить?',
          missingField: 'eventId',
          action: 'delete_event'
        };
      }
    }

    // Mock удаление
    const eventId = params.eventId || `evt_by_title_${params.title}`;

    return {
      success: true,
      action: 'delete_event',
      data: {
        deleted: true,
        eventId: eventId
      },
      message: `✅ Событие "${params.title || 'выбранное'}" удалено из календаря`,
      requiresFollowup: false
    };
  },

  check_availability: async (params) => {
    let checkDate;

    if (params.date) {
      checkDate = new Date(params.date);
    } else {
      // Пытаемся извлечь дату из истории
      const extractedDate = extractMissingParamsFromHistory('datetime', messageHistory);
      if (extractedDate) {
        checkDate = new Date(extractedDate);
      } else {
        checkDate = new Date(); // Сегодня
      }
    }

    const dateStr = checkDate.toLocaleDateString('ru-RU', {
      timeZone: timezone,
      weekday: 'long',
      day: 'numeric',
      month: 'long'
    });

    // Mock доступные слоты (в production проверить реальный календарь)
    const availableSlots = [
      { start: '09:00', end: '12:00', duration: 180 },
      { start: '14:00', end: '18:00', duration: 240 }
    ];

    const slotsText = availableSlots
      .map(s => `  • ${s.start} - ${s.end} (${s.duration} мин.)`)
      .join('\n');

    return {
      success: true,
      action: 'check_availability',
      data: {
        date: checkDate.toISOString(),
        availableSlots: availableSlots
      },
      message: `🕐 Доступные слоты на ${dateStr}:\n\n${slotsText}`,
      requiresFollowup: false
    };
  }
};

// Главная функция выполнения
async function executeTool() {
  try {
    const tool = calendarTools[task];

    if (!tool) {
      return {
        success: false,
        action: task,
        message: `❌ Неизвестная задача: ${task}. Доступные: create_event, read_events, update_event, delete_event, check_availability`,
        requiresFollowup: true,
        error: 'Unknown task'
      };
    }

    const result = await tool(params);

    return {
      json: {
        ...$input.first().json,
        calendarResult: result,
        agentResponse: result.message,
        requiresFollowup: result.requiresFollowup,
        toolExecuted: task
      }
    };

  } catch (error) {
    console.error('Calendar tool execution error:', error);

    return {
      json: {
        ...$input.first().json,
        calendarResult: {
          success: false,
          action: task,
          message: `❌ Ошибка выполнения: ${error.message}`,
          requiresFollowup: false,
          error: error.message
        },
        agentResponse: `Произошла ошибка при обработке запроса: ${error.message}`,
        error: error.message
      }
    };
  }
}

// Выполнение (синхронно для Code node в n8n)
const result = calendarTools[task] 
  ? calendarTools[task](params) 
  : {
      success: false,
      message: `Неизвестная задача: ${task}`,
      requiresFollowup: true
    };

return [{
  json: {
    ...$input.first().json,
    calendarResult: result,
    agentResponse: result.message,
    requiresFollowup: result.requiresFollowup,
    toolExecuted: task
  }
}];

// === UNIFY AGENT RESPONSES ===
// Приведение ответов от всех агентов к единому формату

const inputData = $input.first().json;
let finalResponse = '';

// Определяем источник ответа
if (inputData.calendarResult) {
  // Ответ от Calendar Agent
  finalResponse = inputData.agentResponse || inputData.calendarResult.message;
} else if (inputData.choices) {
  // Ответ от Default Agent (OpenAI format)
  finalResponse = inputData.choices[0]?.message?.content || 'Извините, не удалось обработать запрос.';
} else if (inputData.agentResponse) {
  // Готовый ответ
  finalResponse = inputData.agentResponse;
} else {
  // Fallback
  finalResponse = '⚠️ Произошла ошибка при обработке запроса. Попробуйте ещё раз.';
}

// Обновляем историю с ответом ассистента
const updatedHistory = [...(inputData.messageHistory || [])];
updatedHistory.push({
  role: 'assistant',
  content: finalResponse,
  timestamp: new Date().toISOString()
});

// Ограничиваем историю
if (updatedHistory.length > 10) {
  updatedHistory.slice(-10);
}

return [{
  json: {
    ...inputData,
    finalResponse: finalResponse,
    updatedHistory: updatedHistory,
    processedAt: new Date().toISOString()
  }
}];

// === UPDATE MEMORY HUB ===
// Сохранение обновлённой истории сессии после обработки запроса

const chatId = $input.first().json.chatId;
const sessionKey = `session:${chatId}`;
const finalResponse = $input.first().json.finalResponse || $input.first().json.agentResponse || 'Ошибка: нет ответа';
const timestamp = new Date().toISOString();

// Получаем текущую историю или создаём новую
let messageHistory = $input.first().json.messageHistory || [];
let session = $input.first().json.session || {};

// Добавляем ответ ассистента в историю
messageHistory.push({
  role: 'assistant',
  content: finalResponse,
  timestamp: timestamp
});

// Ограничиваем историю последними 10 сообщениями
if (messageHistory.length > 10) {
  messageHistory = messageHistory.slice(-10);
}

// Обновляем сессию
session.history = messageHistory;
session.updatedAt = timestamp;
session.lastIntent = $input.first().json.task || session.lastIntent;

// Сохраняем в статические данные workflow
try {
  const staticData = $getWorkflowStaticData();
  if (!staticData.sessions) {
    staticData.sessions = {};
  }
  staticData.sessions[sessionKey] = session;
} catch (error) {
  console.error('Failed to update session in static data:', error.message);
}

return [{
  json: {
    ...$input.first().json,
    memoryUpdated: true,
    updatedHistory: messageHistory,
    session: session
  }
}];

// === GLOBAL ERROR HANDLER ===
// Логирование ошибок и отправка уведомления пользователю

const errorInfo = {
  timestamp: new Date().toISOString(),
  chatId: $input.first().json.chatId || 'unknown',
  errorMessage: $input.first().json.error || 'Unknown error',
  workflowStage: 'final'
};

console.error('Workflow Error:', JSON.stringify(errorInfo));

// Возвращаем понятное сообщение пользователю
return [{
  json: {
    chatId: errorInfo.chatId,
    finalResponse: '⚠️ Произошла ошибка при обработке вашего запроса. Пожалуйста, попробуйте ещё раз позже.',
    errorLogged: true
  }
}];
